exercises.snippet:
class Handler:
    def __init__(self, nxt=None):
        self.nxt = nxt
    def handle(self, r):
        if self.nxt:
            return self.nxt.handle(r)
        return "none"

class A(Handler):
    def handle(self, r):
        return "A" if r == "a" else super().handle(r)

class B(Handler):
    def handle(self, r):
        return "B" if r == "b" else super().handle(r)

chain = A(B())
print(chain.handle("b"))
print(chain.handle("x"))

